    @RustCleanup("Remove in V16.") // Not in libAnki
    fun findOneCardByNote(query: String, order: SortOrder = SortOrder.NoOrdering()): List<CardId> {
        // This function shouldn't exist and CardBrowser should be modified to use Notes,
        // so not much effort was expended here

        val noteIds = findNotes(query, order)
        // select the card with the lowest `ord` to show
        val cardIdsByNoteId = db.queryLongList(
            """
SELECT c.id, c.nid
FROM (
  SELECT nid, MIN(ord) AS ord
  FROM cards
  WHERE nid IN ${Utils.ids2str(noteIds)} 
  GROUP BY nid
) AS card_with_min_ord
JOIN cards AS c ON card_with_min_ord.nid = c.nid AND card_with_min_ord.ord = c.ord;
            """.trimMargin()
        )
        // If no ordering is requested, return as-is
        if (order is SortOrder.NoOrdering) {
            return cardIdsByNoteId
        }
        // Build a map from noteId to cardId to preserve the ordering from findNotes
        val noteIdToCardId = mutableMapOf<Long, Long>()
        // The query returns pairs of (card_id, note_id) but queryLongList only returns first column
        // We need a different approach: query both columns
        val cardNidPairs = db.query(
            """
SELECT c.id, c.nid
FROM (
  SELECT nid, MIN(ord) AS ord
  FROM cards
  WHERE nid IN ${Utils.ids2str(noteIds)} 
  GROUP BY nid
) AS card_with_min_ord
JOIN cards AS c ON card_with_min_ord.nid = c.nid AND card_with_min_ord.ord = c.ord;
            """.trimMargin()
        )
        cardNidPairs.use { cursor ->
            while (cursor.moveToNext()) {
                noteIdToCardId[cursor.getLong(1)] = cursor.getLong(0)
            }
        }
        // Return card IDs in the same order as the note IDs from findNotes
        return noteIds.mapNotNull { noteIdToCardId[it] }
    }"}

